mapper.select:
SELECT tnpnm.ntnl_pnt_seq, tnpnm.accdnt_area_flag, tnpnm.ntnl_pnt_no, tnpnm.lctn_sign_no, tnpnm.snsr_srl_no, tnpnm.sgg_cd, tcc.cm_nm as sgg_nm, tcc2.cm_nm as instlName, tnpnm.instl_cd, tcc3.cm_nm as instlTypeName, tnpnm.instl_type_cd, tnpnm.x_crdnt, tnpnm.y_crdnt, tnpnm.z_crdnt, tnpnm.lng, tnpnm.lat, tnpnm.hght, tsd.gps_lon_ref_value AS snsr_lng, tsd.gps_lat_ref_value AS snsr_lat, tnpnm.srt_sq, tnpnm.use_flag, tnpnm.rgst_date_time, tnpnm.upt_date_time FROM tb_ntnl_pnt_no_m tnpnm LEFT OUTER JOIN tb_com_cd tcc ON tnpnm.sgg_cd = tcc.cm_std_cd LEFT OUTER JOIN tb_com_cd tcc2 ON tnpnm.instl_cd = tcc2.cm_std_cd LEFT OUTER JOIN tb_com_cd tcc3 ON tnpnm.instl_type_cd = tcc3.cm_std_cd LEFT OUTER JOIN ( SELECT a.ntnl_pnt_no ,a.ntnl_pnt_seq ,gps_lon_ref_value ,gps_lat_ref_value FROM tb_snsr_data a INNER JOIN ( SELECT MAX(snsr_data_seq) AS snsr_data_seq ,ntnl_pnt_seq FROM tb_snsr_data GROUP BY ntnl_pnt_seq ) b ON a.ntnl_pnt_seq = b.ntnl_pnt_seq AND a.snsr_data_seq = b.snsr_data_seq ) tsd ON tnpnm.ntnl_pnt_seq = tsd.ntnl_pnt_seq WHERE 1=1
AND tnpnm.sgg_cd = #{sggCd}
AND (tnpnm.ntnl_pnt_no LIKE CONCAT('%',#{searchText},'%') OR tnpnm.lctn_sign_no LIKE CONCAT('%',#{searchText},'%'))
AND tnpnm.instl_cd = #{instlCd}
ORDER BY tnpnm.SRT_SQ
